namespace sv_f2bab1badc2e44318bf254573c705771.Client.Models;

public sealed class Shipment
{
    public required string TrackingNumber { get; init; }
    public required string Status { get; init; }
    public required string Location { get; init; }
    public required DateTimeOffset EstimatedDelivery { get; init; }
    public required IReadOnlyList<StatusUpdate> StatusUpdates { get; init; }
}

public sealed class StatusUpdate
{
    public required string Description { get; init; }
    public required DateTimeOffset Timestamp { get; init; }
}

using sv_f2bab1badc2e44318bf254573c705771.Client.Models;

namespace sv_f2bab1badc2e44318bf254573c705771.Client.Services;

public interface IShipmentService
{
    Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

using System.Net;
using System.Net.Http.Json;
using sv_f2bab1badc2e44318bf254573c705771.Client.Models;

namespace sv_f2bab1badc2e44318bf254573c705771.Client.Services;

public sealed class ShipmentHttpClient(HttpClient http) : IShipmentService
{
    public async Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        var response = await http.GetAsync($"api/shipments/{Uri.EscapeDataString(trackingNumber)}", ct);

        if (response.StatusCode == HttpStatusCode.NotFound)
        {
            return null;
        }

        response.EnsureSuccessStatusCode();
        return await response.Content.ReadFromJsonAsync<Shipment>(ct);
    }
}

using sv_f2bab1badc2e44318bf254573c705771.Client.Models;
using sv_f2bab1badc2e44318bf254573c705771.Client.Services;

namespace sv_f2bab1badc2e44318bf254573c705771.Services;

public sealed class ServerShipmentService : IShipmentService
{
    private static readonly Dictionary<string, Shipment> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["PKG-001"] = new Shipment
        {
            TrackingNumber = "PKG-001",
            Status = "In Transit",
            Location = "Chicago, IL",
            EstimatedDelivery = new DateTimeOffset(2026, 6, 2, 17, 0, 0, TimeSpan.FromHours(-5)),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Package picked up", Timestamp = new DateTimeOffset(2026, 5, 25, 9, 0, 0, TimeSpan.FromHours(-5)) },
                new StatusUpdate { Description = "Arrived at sorting facility", Timestamp = new DateTimeOffset(2026, 5, 26, 3, 30, 0, TimeSpan.FromHours(-5)) },
                new StatusUpdate { Description = "Departed sorting facility", Timestamp = new DateTimeOffset(2026, 5, 26, 14, 15, 0, TimeSpan.FromHours(-5)) },
                new StatusUpdate { Description = "In transit to destination hub", Timestamp = new DateTimeOffset(2026, 5, 27, 8, 45, 0, TimeSpan.FromHours(-5)) },
            ]
        },
        ["PKG-002"] = new Shipment
        {
            TrackingNumber = "PKG-002",
            Status = "Delivered",
            Location = "Austin, TX",
            EstimatedDelivery = new DateTimeOffset(2026, 5, 27, 12, 0, 0, TimeSpan.FromHours(-6)),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Package picked up", Timestamp = new DateTimeOffset(2026, 5, 22, 10, 0, 0, TimeSpan.FromHours(-6)) },
                new StatusUpdate { Description = "Arrived at regional hub", Timestamp = new DateTimeOffset(2026, 5, 23, 6, 0, 0, TimeSpan.FromHours(-6)) },
                new StatusUpdate { Description = "Out for delivery", Timestamp = new DateTimeOffset(2026, 5, 27, 7, 30, 0, TimeSpan.FromHours(-6)) },
                new StatusUpdate { Description = "Delivered — signed by J. Smith", Timestamp = new DateTimeOffset(2026, 5, 27, 11, 45, 0, TimeSpan.FromHours(-6)) },
            ]
        },
        ["PKG-003"] = new Shipment
        {
            TrackingNumber = "PKG-003",
            Status = "Processing",
            Location = "Seattle, WA",
            EstimatedDelivery = new DateTimeOffset(2026, 6, 5, 18, 0, 0, TimeSpan.FromHours(-7)),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Order placed", Timestamp = new DateTimeOffset(2026, 5, 27, 20, 0, 0, TimeSpan.FromHours(-7)) },
                new StatusUpdate { Description = "Label created", Timestamp = new DateTimeOffset(2026, 5, 28, 0, 15, 0, TimeSpan.FromHours(-7)) },
            ]
        }
    };

    public async Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        await Task.Delay(1500, ct);

        SeedData.TryGetValue(trackingNumber, out var shipment);
        return shipment;
    }
}

@page "/shipments/{TrackingNumber}"
@rendermode InteractiveAuto
@using sv_f2bab1badc2e44318bf254573c705771.Client.Models
@using sv_f2bab1badc2e44318bf254573c705771.Client.Services
@inject IShipmentService ShipmentService
@inject ILogger<ShipmentTracker> Logger
@implements IAsyncDisposable

<PageTitle>Shipment @TrackingNumber</PageTitle>

@if (_loading)
{
    <p><em>Loading shipment @TrackingNumber…</em></p>
}
else if (_errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_errorMessage</p>
        <button class="btn btn-outline-danger btn-sm" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_shipment is null)
{
    <div class="alert alert-warning" role="alert">
        <p>No shipment found for tracking number <strong>@TrackingNumber</strong>.</p>
    </div>
}
else
{
    <h3>Shipment @_shipment.TrackingNumber</h3>
    <dl>
        <dt>Status</dt>
        <dd>@_shipment.Status</dd>
        <dt>Location</dt>
        <dd>@_shipment.Location</dd>
        <dt>Estimated Delivery</dt>
        <dd>@_shipment.EstimatedDelivery.ToString("f")</dd>
    </dl>

    <h4>Status Updates</h4>
    @if (_shipment.StatusUpdates.Count == 0)
    {
        <p>No status updates yet.</p>
    }
    else
    {
        <table class="table table-striped">
            <thead>
                <tr>
                    <th>Time</th>
                    <th>Description</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var update in _shipment.StatusUpdates)
                {
                    <tr>
                        <td>@update.Timestamp.ToString("g")</td>
                        <td>@update.Description</td>
                    </tr>
                }
            </tbody>
        </table>
    }
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = default!;

    private Shipment? _shipment;
    private bool _loading;
    private string? _errorMessage;

    private CancellationTokenSource _cts = new();

    protected override async Task OnParametersSetAsync()
    {
        // Cancel any in-flight request when the tracking number changes or on first load.
        await CancelPendingAsync();
        _cts = new CancellationTokenSource();
        await LoadShipmentAsync(_cts.Token);
    }

    private async Task LoadShipmentAsync(CancellationToken ct)
    {
        _loading = true;
        _errorMessage = null;
        _shipment = null;

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, ct);
        }
        catch (OperationCanceledException) when (ct.IsCancellationRequested)
        {
            // Navigation away or parameter change — silently abandon.
            return;
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout fetching shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (TaskCanceledException ex) when (ex.InnerException is TimeoutException)
        {
            Logger.LogError(ex, "Timeout fetching shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error fetching shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "Something went wrong loading the shipment. Please try again.";
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task RetryAsync()
    {
        await CancelPendingAsync();
        _cts = new CancellationTokenSource();
        await LoadShipmentAsync(_cts.Token);
    }

    private async ValueTask CancelPendingAsync()
    {
        await _cts.CancelAsync();
        _cts.Dispose();
    }

    public async ValueTask DisposeAsync()
    {
        await CancelPendingAsync();
    }
}

